#include <bits/stdc++.h>
using namespace std;

const int N=3e5+10,V=1e6+10;

struct Node{
    int t,x,y,id;
}q[N<<1],tmp[N<<1];

int n,m,c[V],ans[N<<1];

void add(int x,int k){
    for(;x<V;x+=(x&(-x)))
        c[x]=max(c[x],k);
}

int ask(int x){
    int res=c[0];
    for(;x;x-=(x&(-x)))
        res=max(res,c[x]);
    return res;
}

void del(int x){
    for(;x<V && c[x]>c[0];x+=(x&(-x)))
        c[x]=c[0];
}

void CDQ(int l,int r){
    if(l==r)
        return;
    int mid=l+r>>1;
    CDQ(l,mid);
    CDQ(mid+1,r);
    for(int i=mid+1,j=l;i<=r;i++){
        while(j<=mid && q[i].x>=q[j].x){
            if(q[j].t==1)
            	add(q[j].y,q[j].x+q[j].y);
			j++;
		}
        if(q[i].t==2)
            ans[q[i].id]=min(ans[q[i].id],q[i].x+q[i].y-ask(q[i].y));
    }
    for(int j=l;j<=mid;j++)
        if(q[j].t==1)
            del(q[j].y);
    // 计算 x[i]>=x[j],y[i]>=y[j] 的贡献

    for(int i=mid+1,j=l;i<=r;i++){
        while(j<=mid && q[i].x>=q[j].x){
            if(q[j].t==1)
            	add(V-q[j].y,q[j].x-q[j].y);
			j++;
		}
        if(q[i].t==2)
            ans[q[i].id]=min(ans[q[i].id],q[i].x-q[i].y-ask(V-q[i].y));
    }
    for(int j=l;j<=mid;j++)
        if(q[j].t==1)
            del(V-q[j].y);
    // 计算 x[i]>=x[j],y[i]<y[j] 的贡献

    for(int i=r,j=mid;i>mid;i--){
        while(j>=l && q[i].x<q[j].x){
            if(q[j].t==1)
            	add(q[j].y,q[j].y-q[j].x);
			j--;
		}
        if(q[i].t==2)
            ans[q[i].id]=min(ans[q[i].id],q[i].y-q[i].x-ask(q[i].y));
    }
    for(int j=l;j<=mid;j++)
        if(q[j].t==1)
            del(q[j].y);
    // 计算 x[i]<x[j],y[i]>=y[j] 的贡献

    for(int i=r,j=mid;i>mid;i--){
        while(j>=l && q[i].x<q[j].x){
            if(q[j].t==1)
				add(V-q[j].y,-q[j].x-q[j].y);
			j--;
		}
        if(q[i].t==2)
            ans[q[i].id]=min(ans[q[i].id],-q[i].x-q[i].y-ask(V-q[i].y));
    }
    for(int j=l;j<=mid;j++)
        if(q[j].t==1)
            del(V-q[j].y);
    // 计算 x[i]<x[j],y[i]<y[j] 的贡献

    for(int i=l,j=mid+1;i<=mid || j<=r;)
        if(i<=mid && (j>r || q[i].x<=q[j].x))
            tmp[i+j-mid-1]=q[i],i++;
        else
            tmp[i+j-mid-1]=q[j],j++;
    for(int i=l;i<=r;i++)
        q[i]=tmp[i];
    // 合并两段
}

int main(){
    memset(c,0xcf,sizeof(c));
    memset(ans,0x3f,sizeof(ans));
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        q[i].t=1;
        scanf("%d%d",&q[i].x,&q[i].y);
        q[i].id=i,q[i].x++,q[i].y++;
    }
    for(int i=1;i<=m;i++){
        scanf("%d%d%d",&q[n+i].t,&q[n+i].x,&q[n+i].y);
        q[n+i].id=n+i,q[n+i].x++,q[n+i].y++;
    }
    CDQ(1,n+m);
    /*
    for(int i=1;i<=n+m;i++)
    	printf("%d %d %d %d\n",q[i].t,q[i].x,q[i].y,q[i].id);
    */
    for(int i=n+1;i<=n+m;i++)
    	if(ans[i]<=1e9)
    		printf("%d\n",ans[i]);
    return 0;
}
